    ('RU000A10D533', DATE '2026-02-27', 92.495, 'SUR', 1000, 'RUB', 45.59),
    ('RU000A10D533', DATE '2026-03-02', 92.3, 'SUR', 1000, 'RUB', 46.66),
    ('RU000A10D533', DATE '2026-03-03', 92.199, 'SUR', 1000, 'RUB', 47.01),
    ('RU000A10D533', DATE '2026-03-04', 92.13, 'SUR', 1000, 'RUB', 47.37),
    ('RU000A10D533', DATE '2026-03-05', 91.998, 'SUR', 1000, 'RUB', 47.72),
    ('RU000A10D533', DATE '2026-03-06', 92.011, 'SUR', 1000, 'RUB', 48.08),
    ('RU000A10D533', DATE '2026-03-09', 92.245, 'SUR', 1000, 'RUB', 49.15),
    ('RU000A10D533', DATE '2026-03-10', 91.91, 'SUR', 1000, 'RUB', 49.51),
    ('RU000A10D533', DATE '2026-03-11', 91.88, 'SUR', 1000, 'RUB', 49.86),
    ('RU000A10D533', DATE '2026-03-12', 92.563, 'SUR', 1000, 'RUB', 50.22),
    ('RU000A10D533', DATE '2026-03-13', 93.199, 'SUR', 1000, 'RUB', 50.57),
    ('RU000A10D533', DATE '2026-03-16', 93.3, 'SUR', 1000, 'RUB', 51.64),
    ('RU000A10D533', DATE '2026-03-17', 92.98, 'SUR', 1000, 'RUB', 52),
    ('RU000A10D533', DATE '2026-03-18', 92.999, 'SUR', 1000, 'RUB', 52.35),
    ('RU000A10D533', DATE '2026-03-19', 92.94, 'SUR', 1000, 'RUB', 52.71),
    ('RU000A10D533', DATE '2026-03-20', 93, 'SUR', 1000, 'RUB', 53.07),
    ('RU000A10D533', DATE '2026-03-23', 92.9, 'SUR', 1000, 'RUB', 54.14),
    ('RU000A10D533', DATE '2026-03-24', 92.8, 'SUR', 1000, 'RUB', 54.49),
    ('RU000A10D533', DATE '2026-03-25', 93, 'SUR', 1000, 'RUB', 54.85),
    ('RU000A10D533', DATE '2026-03-26', 92.741, 'SUR', 1000, 'RUB', 55.2),
    ('RU000A10D533', DATE '2026-03-27', 92.639, 'SUR', 1000, 'RUB', 55.56)
),
resolved_base AS (
    SELECT
        i.id AS instrument_id,
        s.trade_date,
        i.type AS instrument_type,
        s.raw_price,
        CASE
            WHEN upper(coalesce(s.trade_currency_id, '')) IN ('SUR', 'RUR') THEN 'RUB'
            WHEN nullif(upper(coalesce(s.trade_currency_id, '')), '') IS NULL THEN i.currency_id
            ELSE upper(s.trade_currency_id)
        END AS trade_currency_id,
        s.face_value,
        CASE
            WHEN upper(coalesce(s.face_currency_id, '')) IN ('SUR', 'RUR') THEN 'RUB'
            WHEN nullif(upper(coalesce(s.face_currency_id, '')), '') IS NULL THEN i.currency_id
            ELSE upper(s.face_currency_id)
        END AS face_currency_id,
        coalesce(s.accrued_interest, 0) AS accrued_interest,
        i.currency_id,
        md5(i.id::text || '|' || s.trade_date::text || '|MOEX') AS hash_key
    FROM src s
    JOIN instruments i ON upper(i.ticker) = s.ticker
),
resolved AS (
    SELECT
        rb.instrument_id,
        rb.trade_date,
        CASE
            WHEN rb.instrument_type = 2 AND coalesce(rb.face_value, 0) > 0 THEN (
                CASE
                    WHEN rb.face_currency_id = rb.currency_id THEN (rb.raw_price / 100.0) * rb.face_value
                    WHEN clean_direct.rate IS NOT NULL THEN ((rb.raw_price / 100.0) * rb.face_value) * clean_direct.rate
                    WHEN clean_inverse.rate IS NOT NULL AND clean_inverse.rate <> 0 THEN ((rb.raw_price / 100.0) * rb.face_value) / clean_inverse.rate
                    ELSE (rb.raw_price / 100.0) * rb.face_value
                END
                +
                CASE
                    WHEN rb.accrued_interest = 0 THEN 0
                    WHEN rb.trade_currency_id = rb.currency_id THEN rb.accrued_interest
                    WHEN accrued_direct.rate IS NOT NULL THEN rb.accrued_interest * accrued_direct.rate
                    WHEN accrued_inverse.rate IS NOT NULL AND accrued_inverse.rate <> 0 THEN rb.accrued_interest / accrued_inverse.rate
                    ELSE rb.accrued_interest
                END
            )::numeric(18,4)
            ELSE rb.raw_price::numeric(18,4)
        END AS price,
        rb.currency_id,
        rb.hash_key
    FROM resolved_base rb
    LEFT JOIN LATERAL (
        SELECT fx.rate
        FROM fx_rates fx
        WHERE fx.base_currency_id = rb.face_currency_id
          AND fx.quote_currency_id = rb.currency_id
          AND fx.date::date <= rb.trade_date
        ORDER BY fx.date DESC, fx.created_at DESC
        LIMIT 1
    ) AS clean_direct ON true
    LEFT JOIN LATERAL (
        SELECT fx.rate
        FROM fx_rates fx
        WHERE fx.base_currency_id = rb.currency_id
          AND fx.quote_currency_id = rb.face_currency_id
          AND fx.date::date <= rb.trade_date
        ORDER BY fx.date DESC, fx.created_at DESC
        LIMIT 1
    ) AS clean_inverse ON true
    LEFT JOIN LATERAL (
        SELECT fx.rate
        FROM fx_rates fx
        WHERE fx.base_currency_id = rb.trade_currency_id
          AND fx.quote_currency_id = rb.currency_id
          AND fx.date::date <= rb.trade_date
        ORDER BY fx.date DESC, fx.created_at DESC
        LIMIT 1
    ) AS accrued_direct ON true
    LEFT JOIN LATERAL (
        SELECT fx.rate
        FROM fx_rates fx
        WHERE fx.base_currency_id = rb.currency_id
          AND fx.quote_currency_id = rb.trade_currency_id
          AND fx.date::date <= rb.trade_date
        ORDER BY fx.date DESC, fx.created_at DESC
        LIMIT 1
    ) AS accrued_inverse ON true
)
INSERT INTO prices (id, instrument_id, date, value, currency_id, provider, created_at, updated_at)
SELECT
    (
        substr(hash_key, 1, 8) || '-' ||
        substr(hash_key, 9, 4) || '-' ||
        substr(hash_key, 13, 4) || '-' ||
        substr(hash_key, 17, 4) || '-' ||
        substr(hash_key, 21, 12)
    )::uuid,
    instrument_id,
    (trade_date::timestamp AT TIME ZONE 'UTC'),
    price,
    currency_id,
    'MOEX',
    now(),
    now()
FROM resolved
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    updated_at = now();

COMMIT;

-- Source: scripts/moex_history/sql/hrl_rm_otc_fix.sql (price part only)

BEGIN;

WITH hrl AS (
    SELECT id
    FROM instruments
    WHERE isin = 'US4404521001'
    ORDER BY created_at
    LIMIT 1
)
DELETE FROM prices
WHERE instrument_id = (SELECT id FROM hrl)
  AND provider = 'MOEX'
  AND date::date IN ('2026-03-16', '2026-03-17', '2026-03-20');

WITH hrl AS (
    SELECT id
    FROM instruments
    WHERE isin = 'US4404521001'
    ORDER BY created_at
    LIMIT 1
)
INSERT INTO prices (
    id,
    instrument_id,
    date,
    value,
    currency_id,
    source_currency_id,
    provider,
    created_at,
    updated_at
)
SELECT gen_random_uuid(), hrl.id, v.date, v.value, 'RUB', 'RUB', 'MOEX', now(), now()
FROM hrl
CROSS JOIN (
    VALUES
        ('2026-03-16'::date, 370.0::numeric),
        ('2026-03-17'::date, 370.0::numeric),
        ('2026-03-20'::date, 372.0::numeric)
) AS v(date, value)
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    source_currency_id = EXCLUDED.source_currency_id,
    updated_at = now();

COMMIT;

-- Source: scripts/moex_history/sql/report_2026_mts_2p17.sql (MOEX price rows only)

BEGIN;

WITH instrument_ref AS (
    SELECT id
    FROM instruments
    WHERE ticker = 'RU000A10ELF6'
),
price_rows AS (
    SELECT * FROM (
        VALUES
            ('2026-03-18'::date, 995.3000::numeric, 'RUB'::varchar),
            ('2026-03-19'::date, 998.3700::numeric, 'RUB'::varchar),
            ('2026-03-20'::date, 998.9400::numeric, 'RUB'::varchar)
    ) AS v(price_date, value, currency_id)
)
INSERT INTO prices (
    id,
    instrument_id,
    date,
    value,
    currency_id,
    provider,
    created_at,
    updated_at,
    source_currency_id
)
SELECT
    gen_random_uuid(),
    instrument_ref.id,
    price_rows.price_date::timestamp AT TIME ZONE 'UTC',
    price_rows.value,
    price_rows.currency_id,
    'MOEX',
    now(),
    now(),
    NULL
FROM instrument_ref
CROSS JOIN price_rows
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    updated_at = now(),
    source_currency_id = EXCLUDED.source_currency_id;

COMMIT;
